import{a as r}from"./vendor-query-DGlGczoo.js";const c={async getCommissionPercent(o){try{return(await r.get(`${"http://localhost:9084/".replace(/\/$/,"")}/api/v1/commission-rules/product/${o}`,{headers:{Authorization:`Bearer ${localStorage.getItem("authToken")}`}})).data.commissionPercent||0}catch(e){return console.error("Error fetching commission percent:",e),0}},async calculateCommission(o){try{if(!o.policy_name_id||o.premium_amount===void 0)return{calculated_commission_amount:0,base_percentage:0,rule_found:!1};const e=await this.getCommissionPercent(o.policy_name_id);if(e===0)return{calculated_commission_amount:0,base_percentage:0,rule_found:!1};const n=o.premium_amount*e/100;return console.log("🔍 [Service Debug] Commission calculation:",{commissionPercent:e,premiumAmount:o.premium_amount,calculatedCommission:n}),{calculated_commission_amount:n,base_percentage:e,rule_found:!0}}catch(e){return console.error("Error calculating commission:",e),{calculated_commission_amount:0,base_percentage:0,rule_found:!1}}}};export{c};
